new Valine(VALINE_CONFIG);const color=["#49c085","#f2b63c","#f58a87","#6f92ff","#7782d1","#d56464"];let myChart=echarts.init($(".chart")[0]);let option={left:"100%",top:"100%",title:{text:"个人技能"},tooltip:{},legend:{show:true},yAxis:{name:"分数",min:0,max:100}};myChart.showLoading();$.ajax({url:"/skill",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200){let data=[];let xAxis=[];for(let i=0;i<a.data.length;i++){if(a.data[i].status===1){data.push({name:a.data[i].name,value:a.data[i].percent,itemStyle:{color:color[i%color.length]}});xAxis.push(a.data[i].name)}}myChart.hideLoading();option.xAxis={name:"技能",position:"bottom",data:xAxis};option.series=[{name:"技能",type:"bar",label:{show:true,position:"top"},data:data}];myChart.setOption(option)}}});$(window).resize(function(){myChart.resize()});